                if (slowrf_reporting) {
                    // FS20 Check
                    if (dec.byte_cnt >= 4) {
                        char out[64];
                        int len = snprintf(out, sizeof(out), "F");
                        for (int i = 0; i < dec.byte_cnt; i++) {
                            len += snprintf(out + len, sizeof(out) - len, "%02X", dec.data[i]);
                        }
